#include <stdio.h>
#include <string.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, K; scanf("%d %d", &N, &K);
        int F[1005];
        for(int i=1;i<=N;i++) scanf("%d", &F[i]);
        int dp[1005];
        const int INF = 1e9;
        dp[0]=0;
        for(int i=1;i<=N;i++) dp[i]=INF;
        for(int i=1;i<=N;i++){
            int freq[101];
            memset(freq,0,sizeof(freq));
            int dup=0;
            for(int j=i;j>=1;j--){
                int fam=F[j];
                freq[fam]++;
                if(freq[fam]==2) dup+=2; // both guests now count
                else if(freq[fam]>2) dup+=1; // new guest adds one more duplicate
                int cost = dp[j-1] + K + dup;
                if(cost < dp[i]) dp[i]=cost;
            }
        }
        printf("%d\n", dp[N]);
    }
    return 0;
}

