            st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            int K = Integer.parseInt(st.nextToken());
            int[] F = new int[N+1];
            st = new StringTokenizer(br.readLine());
            for (int i = 1; i <= N; i++) {
                F[i] = Integer.parseInt(st.nextToken());
            }
            int INF = 1_000_000_000;
            int[] dp = new int[N+1];
            Arrays.fill(dp, INF);
            dp[0] = 0;
            for (int i = 1; i <= N; i++) {
                int[] freq = new int[101];
                int dup = 0;
                for (int j = i; j >= 1; j--) {
                    int fam = F[j];
                    freq[fam]++;
